{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental domain model change that redefines what a Shipment means — it shifts from 'a package going to a person' to 'a package going to potentially multiple people with individual delivery preferences.' This has cascading implications for fulfillment, routing, notifications, billing, and external integrations.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods in transit from sender to one or more recipients. The root aggregate that tracks lifecycle from creation through delivery." },
      { "term": "Recipient", "definition": "A party designated to receive a shipment, characterized by name, address, phone number, and delivery preferences. Now a child entity within the Shipment aggregate rather than a value object." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how delivery should be handled — e.g., safe place, neighbor delivery, time window, signature requirement." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a multi-recipient shipment. Critical for backward compatibility and for cases where a single point of contact is needed (e.g., failed delivery escalation)." },
      { "term": "Delivery Attempt", "definition": "A courier's effort to deliver to a specific recipient. In the new model, a single shipment may have independent delivery attempts per recipient." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. In a multi-recipient model, aggregate status must now be derived from the individual recipient delivery statuses." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient is physically undeliverable and logically meaningless. This is a data integrity constraint — the system is in a corrupt state if a shipment exists with zero recipients.",
      "testable_assertion": "Creating or updating a Shipment with an empty recipients list must be rejected. Removing the last recipient from a Shipment must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient must have a name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required for a courier to physically locate the destination and contact the recipient. Without them, delivery cannot be attempted.",
      "testable_assertion": "A Recipient with a null or empty name, address, or phone number must be rejected at creation and update time."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment must have a unique address.",
      "invariant": false,
      "invariant_justification": "This is a business policy to prevent accidental duplication, not a physical constraint. A VP could decide to allow two recipients at the same address (e.g., different apartment units with the same building address). However, exact duplicate name+address combinations should be flagged.",
      "testable_assertion": "Adding a Recipient with an address identical to an existing Recipient on the same Shipment should produce a warning or rejection depending on policy configuration."
    },
    {
      "id": "BR-4",
      "rule": "Delivery Preferences are optional and default to standard delivery if not specified by a Recipient.",
      "invariant": false,
      "invariant_justification": "This is a business policy. Defaults can change over time. The system must function without explicit preferences.",
      "testable_assertion": "A Recipient created without explicit delivery preferences must be assigned the standard/default delivery preference set."
    },
    {
      "id": "BR-5",
      "rule": "A Shipment's aggregate status must reflect the combined delivery state of all its Recipients. A Shipment is 'Delivered' only when ALL Recipients have received delivery.",
      "invariant": true,
      "invariant_justification": "If any recipient has not received their delivery, the shipment is not complete. Marking it delivered prematurely would corrupt the fulfillment record and could halt retry logic.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must have status 'Partially Delivered' or 'In Progress', never 'Delivered'."
    },
    {
      "id": "BR-6",
      "rule": "Existing single-recipient shipments must remain valid and functional without data migration. The new model must treat legacy 1:1 data as a shipment with exactly one recipient.",
      "invariant": true,
      "invariant_justification": "2 million production records cannot be corrupted or made inaccessible. Backward compatibility is a data integrity constraint during and after migration.",
      "testable_assertion": "All existing shipments with a single recipient must be queryable, updatable, and displayable without error after the model change is deployed."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in the current single-recipient format unless and until partners explicitly opt in to the multi-recipient format.",
      "invariant": true,
      "invariant_justification": "Breaking partner integrations is a contract violation, not a policy choice. Partners have built systems against the existing schema. Unilateral format changes will cause data loss and integration failures.",
      "testable_assertion": "Partner API payloads for shipments with multiple recipients must flatten to the primary recipient's data by default. Partners on the v2 API must receive the full recipient list."
    },
    {
      "id": "BR-8",
      "rule": "A multi-recipient Shipment must designate exactly one Primary Recipient.",
      "invariant": true,
      "invariant_justification": "The primary recipient serves as the single point of contact for failed delivery escalation, billing disputes, and backward-compatible API responses. Without one, the system cannot determine who to contact or what to send partners.",
      "testable_assertion": "A Shipment with multiple recipients but no designated primary must be rejected. Removing the primary designation without reassigning it must be rejected."
    },
    {
      "id": "BR-9",
      "rule": "Notifications (SMS, email, push) must be sent to each Recipient individually based on their own delivery status and preferences.",
      "invariant": false,
      "invariant_justification": "This is a business policy. A VP could decide to only notify the primary recipient. But the default behavior should be per-recipient notifications.",
      "testable_assertion": "When Recipient A's delivery is completed but Recipient B's is pending, only Recipient A receives a delivery confirmation. Recipient B receives no false confirmation."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator provides two or more Recipients with valid name, address, phone, and optional delivery preferences",
      "then": "The Shipment is created with all Recipients, the first Recipient is designated as Primary by default, and the Shipment status is set to 'Created'"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the model change",
      "when": "The Shipment is retrieved via any API or UI",
      "then": "It is returned with the existing recipient as a list of one, with that recipient marked as Primary, and no data loss occurs"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where one Recipient has been delivered to",
      "when": "The Shipment status is queried",
      "then": "The status reflects 'Partially Delivered' (or equivalent), not 'Delivered'"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment exists",
      "when": "An external partner API requests the Shipment data in v1 format",
      "then": "The response contains only the Primary Recipient's data in the original flat schema, with no breaking changes"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment exists",
      "when": "A user attempts to remove the last Recipient",
      "then": "The operation is rejected with a clear error stating a Shipment must have at least one Recipient"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment with Recipients having different delivery preferences",
      "when": "Delivery is attempted for each Recipient",
      "then": "Each delivery attempt respects the individual Recipient's preferences (e.g., safe place for one, signature required for another)"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with 3 Recipients",
      "when": "All 3 Recipients have confirmed delivery",
      "then": "The Shipment aggregate status transitions to 'Delivered'"
    },
    {
      "id": "AC-8",
      "given": "The Primary Recipient is removed from a multi-recipient Shipment",
      "when": "The removal is processed",
      "then": "The system requires a new Primary to be designated before the removal is committed, OR automatically promotes the next Recipient"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where one Recipient's address becomes invalid after creation (e.g., address verification fails at delivery time)",
      "expected_behavior": "The individual Recipient's delivery is marked as 'Undeliverable'. The Shipment remains active for the other Recipients. The sender is notified about the failed Recipient specifically."
    },
    {
      "scenario": "Two Recipients on the same Shipment have the same address but different delivery preferences",
      "expected_behavior": "Both Recipients are valid. The courier receives two separate delivery instructions for the same address. Operationally this may be optimized into one stop, but the system must track two distinct delivery confirmations."
    },
    {
      "scenario": "A partner API webhook fires on shipment status change, but the Shipment is partially delivered",
      "expected_behavior": "V1 partners receive the Primary Recipient's status only. V2 partners receive the full per-recipient status breakdown. 'Partially Delivered' must map to a v1-compatible status (likely 'In Transit' or a new negotiated status)."
    },
    {
      "scenario": "All Recipients except the Primary have been delivered; the Primary's delivery fails permanently",
      "expected_behavior": "The Shipment cannot be marked 'Delivered'. The Primary Recipient failure must be escalated. The sender must decide whether to reassign, cancel, or retry. Other Recipients' successful deliveries are unaffected."
    },
    {
      "scenario": "A Shipment is created with 50 Recipients",
      "expected_behavior": "The system should enforce a configurable maximum recipient count per Shipment to prevent abuse and operational complexity. The limit is a business policy (invariant: false), suggested default: 10."
    },
    {
      "scenario": "Migration is in progress and a legacy Shipment is updated concurrently",
      "expected_behavior": "The update must succeed regardless of migration state. If the Shipment has not yet been migrated to the new schema, the update path must handle both old and new formats safely."
    },
    {
      "scenario": "Billing and pricing: is a multi-recipient Shipment billed as one shipment or N shipments?",
      "expected_behavior": "This is a critical business decision that must be resolved before implementation. The pricing model directly affects the domain model — if billed per-recipient, each Recipient may need its own cost record."
    }
  ],

  "business_impact": {
    "financial": "High impact. Pricing model must be redefined — multi-recipient shipments could increase revenue per shipment or cannibalize volume if customers consolidate. Billing systems, invoicing, and partner revenue-share agreements must all be updated. Incorrect billing during transition could cause revenue leakage or customer disputes.",
    "operational": "High impact. Courier routing algorithms must account for multiple stops per shipment. Dispatch and sorting systems need to handle split deliveries. Warehouse operations may need to package items separately per recipient. Support teams need new workflows for partial delivery issues. Status tracking dashboards must display per-recipient granularity.",
    "user": "Medium-high impact. Senders get a powerful new feature (gift shipments, multi-office distribution). However, the UI/UX complexity increases — users must manage multiple recipients, understand partial delivery states, and handle per-recipient failures. Recipients may be confused by receiving a shipment they didn't directly order.",
    "risk": "High risk. The 1:1 → 1:N cardinality change touches the core domain model and cascades to every bounded context that references Shipment. Partner API backward compatibility is fragile — any regression breaks external integrations. Data migration of 2M records carries corruption risk. The 'Partially Delivered' status is new and must be handled by every downstream system. Rollback is extremely difficult once multi-recipient shipments exist in production.",
    "stakeholders_affected": [
      { "group": "Senders (Customers)", "impact": "New capability to ship to multiple recipients. Must learn new UI. May see pricing changes." },
      { "group": "Recipients", "impact": "May receive shipments they didn't expect. Delivery preferences are now respected individually, improving experience." },
      { "group": "Couriers/Drivers", "impact": "Must handle split deliveries from a single shipment. Route optimization changes. Proof of delivery needed per recipient." },
      { "group": "External Partners (API consumers)", "impact": "Must be shielded from breaking changes. V1 API must continue working. Partners must be given migration timeline to v2." },
      { "group": "Customer Support", "impact": "New failure modes (partial delivery disputes). Need updated playbooks and tools for per-recipient issue resolution." },
      { "group": "Finance/Billing", "impact": "Pricing model decision required. Invoice format changes. Revenue recognition may be affected by partial deliveries." },
      { "group": "Operations/Dispatch", "impact": "Routing, sorting, and warehouse processes must accommodate multi-recipient shipments." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes the model change but leaves critical business decisions unresolved: (1) pricing/billing model for multi-recipient shipments, (2) what 'Partially Delivered' maps to in v1 partner APIs, (3) whether this is physical splitting of goods or logical fan-out of the same package, (4) maximum recipient limits. These ambiguities affect the domain model design itself, not just implementation. Without clarity on whether recipients share one physical package or each get separate packages, the entire fulfillment and routing model changes fundamentally.",
    "high_confidence_areas": [
      "At least one Recipient invariant",
      "Backward compatibility requirement for 2M existing records",
      "Partner API v1 must not break",
      "Per-recipient delivery preferences and notifications",
      "Need for Primary Recipient designation"
    ],
    "low_confidence_areas": [
      "Physical vs logical multi-recipient — is this one package with multiple contacts, or multiple packages from one shipment?",
      "Billing model — per-shipment or per-recipient pricing",
      "Partial delivery status mapping to v1 API",
      "Maximum recipient count policy",
      "Whether delivery preferences include time windows, and how conflicting time windows across recipients on the same route are resolved"
    ],
    "assumptions": [
      "Multi-recipient means multiple physical deliveries to different addresses, not multiple contacts at one address",
      "The Primary Recipient concept is needed but not explicitly stated in the spec",
      "V1 partner APIs exist and cannot be versioned away immediately",
      "Existing single-recipient data will be migrated lazily or via a compatibility layer, not a bulk migration"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether a multi-recipient Shipment represents one physical package delivered to multiple people (fan-out / split), or a single package with multiple contact persons at potentially one address. This distinction fundamentally changes the domain model: fan-out requires separate tracking, routing, and fulfillment per recipient; multiple contacts requires only a contact list.",
      "affected_stakeholders": ["Operations/Dispatch", "Couriers/Drivers", "Finance/Billing", "Senders"],
      "options": [
        "A) Fan-out model: each Recipient gets a separate physical delivery, possibly from a split shipment",
        "B) Contact list model: one delivery, multiple people who can receive it",
        "C) Hybrid: sender chooses per shipment whether recipients are separate deliveries or alternate contacts"
      ],
      "recommendation": "A) Fan-out model — 'each Recipient can have different delivery preferences' implies separate deliveries, since preferences only matter if delivery is independent."
    },
    {
      "type": "ambiguity",
      "description": "No pricing/billing model specified for multi-recipient shipments. This is not a downstream concern — it affects the domain model (whether Recipients carry cost data) and invariants (whether a Shipment's total cost is a sum of per-recipient costs or a flat rate).",
      "affected_stakeholders": ["Finance/Billing", "Senders", "External Partners"],
      "options": [
        "A) Flat rate per Shipment regardless of recipient count",
        "B) Base rate + per-recipient surcharge",
        "C) Each Recipient billed as an independent delivery"
      ],
      "recommendation": "B) Base rate + per-recipient surcharge — balances revenue capture with customer value proposition of consolidation."
    },
    {
      "type": "missing_context",
      "description": "No specification for how 'Partially Delivered' status maps to v1 partner API responses. Partners built against a status enum that likely does not include this state. Sending an unknown status could break partner systems.",
      "affected_stakeholders": ["External Partners", "Operations/Dispatch"],
      "options": [
        "A) Map 'Partially Delivered' to 'In Transit' for v1 partners",
        "B) Add 'Partially Delivered' to v1 enum (breaking change)",
        "C) Send v1 partners the Primary Recipient's individual status only"
      ],
      "recommendation": "C) Send Primary Recipient's individual status — this is fully backward compatible and semantically correct from the v1 perspective where only one recipient exists."
    }
  ],

  "rejection_reasons": []
}

